local http = require "resty.http"
local httpc = http.new()

local url = ngx.var.arg_url
if not url then
    ngx.status = 400
    ngx.say("URL parameter is required")
    ngx.exit(400)
end

-- Validate URL format
if not string.match(url, "^https?://") then
    ngx.status = 400
    ngx.say("Invalid URL format")
    ngx.exit(400)
end

-- Basic URL sanitization
local sanitized_url = string.gsub(url, "[^%w%-%.%_%~%/%%?%#%&%=+]", "")
if sanitized_url ~= url then
    ngx.status = 400
    ngx.say("Invalid characters in URL")
    ngx.exit(400)
end

-- Set timeout and other options
httpc:set_timeouts(10000, 10000, 10000)

local res, err = httpc:request_uri(url, {
    method = ngx.var.request_method,
    headers = ngx.req.get_headers(),
    body = ngx.req.get_body_data(),
    ssl_verify = false,
    keepalive_timeout = 60,
    keepalive_pool = 30
})

if not res then
    ngx.status = 502
    ngx.say("Failed to fetch URL: ", err)
    ngx.exit(502)
end

-- Set response headers
for k, v in pairs(res.headers) do
    if k ~= "connection" and k ~= "keep-alive" then
        ngx.header[k] = v
    end
end

-- Set status
ngx.status = res.status

-- Send response body
ngx.print(res.body)
ngx.exit(res.status)